var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"DOEHYUN_NPC_NULL_NULL","text":{"KOREA":"너, 이 가죽구두가 얼만지 알고 있니?","JPN":"てめえ、この革靴がいくらか知ってんのかよ？","ENG":"You got any idea how much these shoes cost?","TWN":"你知道這雙皮鞋值多少錢嗎？"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DOEHYUN_NPC_NULL_NULL","text":{"KOREA":"너 같은 놈은 평생 서빙을 하며 팁을 긁어 모아도 넘볼 수 없는 가격이라고.","JPN":"てめえみたいな奴が一生皿を運んでチップをかき集めても買えない値段なんだぞ。","ENG":"All the tips you collect in your lifetime won't come even close.","TWN":"像你這種服務生賺一輩子的錢也買不起。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DOEHYUN_NPC_NULL_NULL","text":{"KOREA":"거기에 와인을 쏟아 놓고서 죄송하다 한 마디면 끝날 거 같아?","JPN":"なのにワインをこぼしておいて、申し訳ないの一言で済ませられると思ってるのか？","ENG":"Did you really think saying sorry will save your ass after pouring wine on them?","TWN":"你覺得你說句對不起，我就會原諒你在我的鞋子上撒紅酒嗎？"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"STAFF1_NPC_NULL_NULL","text":{"KOREA":"저, 저기 그러니까...... 죄, 죄송합니다.","JPN":"あのう、ですから……も、申し訳ございません。","ENG":"I-I'm... I'm terribly sorry, sir...","TWN":"不、不是……非、非常抱歉。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"STAFF1_NPC_NULL_NULL","text":{"KOREA":"지금은 없지만 돈은 어떻게든 마련을 해서......","JPN":"すぐには無理ですが、お金はなんとか用意して……","ENG":"I'll find a way to pay you back somehow...","TWN":"雖然我現在沒有錢，但我一定會想辦法湊到錢的……"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DOEHYUN_NPC_NULL_NULL","text":{"KOREA":"이것 봐라. 전혀 반성의 기미가 안 보이잖아?","JPN":"はあ？　まったく反省の気配がないじゃないか。","ENG":"You know what? You don't sound very sorry to me.","TWN":"你這是在反省嗎？"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"STAFF1_NPC_NULL_NULL","text":{"KOREA":"......힉.","JPN":"……ひッ。","ENG":"Eek...","TWN":"……噫。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DOEHYUN_NPC_NULL_NULL","text":{"KOREA":"내가 네놈의 뭘 믿고 기다려주겠냐.","JPN":"てめぇをどう信用しろって？","ENG":"Why should I take your word for it?","TWN":"我憑什麼相信你說的話。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DOEHYUN_NPC_NULL_NULL","text":{"KOREA":"혹시라도 빚 갚기 힘들다고 네놈이 도망이라도 치면 불쌍한 내 구두는 어떡하냐는 거야.","JPN":"弁償金が足りないからってお前が逃げ出したら、かわいそうな俺の靴はどうすりゃいいんだよ。","ENG":"What if you just run away? What am I going to do about my poor shoes then?","TWN":"如果你沒有還完錢就跑路，那我可憐的皮鞋怎麼辦？"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"STAFF1_NPC_NULL_NULL","text":{"KOREA":"저, 절대 그럴 리는 없는......","JPN":"いや、絶対そんなことは……","ENG":"I-I promise that will never—","TWN":"不、不會跑的……"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DOEHYUN_NPC_NULL_NULL","text":{"KOREA":"아아, 닥치고. 그래도 넌 운이 좋아.","JPN":"あーあ、うるせえんだよ。しかしてめえは運がいい。","ENG":"Oh, shut up. You're lucky though.","TWN":"行了，給我閉嘴。你運氣還算不錯。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DOEHYUN_NPC_NULL_NULL","text":{"KOREA":"난 말이지, 돈보다는 재미를 더 중시하는 사람이거든.","JPN":"俺はな、金なんかより楽しさを大事にする人なんでな。","ENG":"I prefer to have fun than make money, you see.","TWN":"比起錢，我更喜歡有趣的事情。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DOEHYUN_NPC_NULL_NULL","text":{"KOREA":"이 석궁에 걸린 깜찍한 화살 보여? 이게 네 빚을 갚게 도와 줄 거야.","JPN":"このボウガンについている素敵な矢が見えるか？　これがてめえの弁償を手伝ってくれるってさ。","ENG":"See this lovely bolt on my crossbow? This will help you pay your debt.","TWN":"看到這把弩弓上面的可愛的箭矢了嗎？這傢伙會幫你還債的。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DOEHYUN_NPC_NULL_NULL","text":{"KOREA":"어이, 저 녀석 벽에 붙여.","JPN":"おい、こいつを壁に張り付けろ。","ENG":"Boys, stand him up against that wall over there.","TWN":"喂，把這傢伙押在牆上。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GUARD_NPC_NULL_NULL","text":{"KOREA":"네! 형님!","JPN":"はい！　兄貴！","ENG":"Yes, sir!","TWN":"是！大哥！"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"STAFF1_NPC_NULL_NULL","text":{"KOREA":"으악, 잠깐...... 잠깐만요! 돈은 사채를 빌려서라도 내일까지 어떻게든......","JPN":"うわっ、ちょっと……ちょっと待ってください！　お金は闇金に借りてでも明日までに何とか……","ENG":"W-wait! I'll pay you back tomorrow, even if I have to take out a loan—","TWN":"啊啊！等……等一下！我會還錢的！我明天去借高利貸……"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DOEHYUN_NPC_NULL_NULL","text":{"KOREA":"썅. 말귀를 못 알아듣는 놈이네. 사채가 얼마나 무서운 건데.","JPN":"黙れ。世間知らずにもほどがある。闇金がどれだけ恐ろしいのか知らねえのか？","ENG":"Tsk, tsk. You don't want to mess with those money mongers, kid.","TWN":"你怎麼聽不懂人話呢，你不知道高利貸有多殘忍嗎。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DOEHYUN_NPC_NULL_NULL","text":{"KOREA":"그런 거 빌려 쓰면 너 인생 종치는 거야.","JPN":"そんなところから金を借りたら、てめえの人生が破綻するに決まってんだろ。","ENG":"That's a surefire way to ruin your life.","TWN":"找高利貸借錢，你這輩子就完了。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DOEHYUN_NPC_NULL_NULL","text":{"KOREA":"평생 빚에 시달릴 바엔 잠깐 따끔하고 마는 게 낫잖아?","JPN":"一生借金に苦しむよりは、一瞬ちくっとして済ませた方がいいじゃないか。","ENG":"Trust me, this will only sting a little. It'll be a hell of a lot better than letting those loan sharks harass you all your life.","TWN":"與其被債務折磨一輩子，痛苦一時、快活一世不是更好嗎？"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DOEHYUN_NPC_NULL_NULL","text":{"KOREA":"다 나같이 착한 사람을 만나서 이런 인생의 충고도 듣는 거라니까.","JPN":"俺のように寛大な人に出会えて、こんな人生のアドバイスまでもらえるだけ感謝しろ。","ENG":"You're lucky you ran into a generous man like me to teach you a life lesson.","TWN":"你要慶幸遇到我這樣善良的人。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};